#include <stddef.h>
#include <string.h>

char *tokenize(const char *string, const char *delimiter) {
    static char output[100000];
    size_t delim_len = strlen(delimiter);
    const char *cursor = string;
    int first = 1;

    output[0] = '\0';
    if (delim_len == 0) {
        if (string[0] != '\0') {
            strcpy(output, string);
        }
        return output;
    }

    while (*cursor != '\0') {
        const char *match = strstr(cursor, delimiter);
        size_t len = match ? (size_t)(match - cursor) : strlen(cursor);
        if (len > 0) {
            if (!first) {
                strcat(output, " ");
            }
            strncat(output, cursor, len);
            first = 0;
        }
        if (!match) {
            break;
        }
        cursor = match + delim_len;
    }

    return output;
}

// C code to demonstrate working of
// strtok
#include <string.h>
#include <stdio.h>

// Driver function
int main()
{
 // Declaration of string
    char gfg[100] = " Hacktober fest by Github";

    // Declaration of delimiter
    const char s[4] = "-";
    char* tok;

    // Use of strtok
    // get first token
    tok = strtok(gfg, s);

    // Checks for delimeter
    while (tok != 0) {
        printf(" %s\n", tok);

        // Use of strtok
        // go through other tokens
        tok = strtok(0, s);
    }

    return (0);
}

import java.util.ArrayList;
import java.util.List;

public class StringToToken {
    public static String[] tokenize(String text, String delimiter) {
        if (text.isEmpty()) {
            return new String[0];
        }
        if (delimiter.isEmpty()) {
            return new String[]{text};
        }
        String[] parts = text.split(java.util.regex.Pattern.quote(delimiter), -1);
        List<String> result = new ArrayList<>();
        for (String part : parts) {
            if (!part.isEmpty()) {
                result.add(part);
            }
        }
        return result.toArray(new String[0]);
    }
}

fun tokenize(text: String, delimiter: String): List<String> {
    if (text.isEmpty()) {
        return emptyList()
    }
    return text.split(delimiter).filter { it.isNotEmpty() }
}

import Foundation

func tokenize(_ string: String, _ delimiter: String) -> [String] {
    if string.isEmpty { return [] }
    if delimiter.isEmpty { return [string] }
    return string
        .components(separatedBy: delimiter)
        .filter { !$0.isEmpty }
}
